'use client';

import { useState } from 'react';
import { TranslatorInput } from '../../components/translator-input';
import { GestureSequencePlayer } from '../../components/gesture-sequence-player';
import { TokenView } from '../../components/token-view';
import { useTranslateText, useTranslateSpeech } from '../../hooks/use-translate';

export default function TranslatorPage() {
  const [text, setText] = useState('');

  const translateText = useTranslateText();
  const translateSpeech = useTranslateSpeech();

  const active = translateSpeech.data ?? translateText.data;
  const isLoading = translateText.isPending || translateSpeech.isPending;
  const error = (translateText.error ?? translateSpeech.error) as Error | null;

  return (
    <div className="grid gap-6 md:grid-cols-2">
      <TranslatorInput
        text={text}
        onTextChange={setText}
        onTranslateText={() => translateText.mutate({ text })}
        onTranslateSpeech={(file: File) => translateSpeech.mutate({ file })}
        loading={isLoading}
        error={error?.message ?? null}
      />

      <div className="rounded-2xl border border-slate-800 bg-slate-900/40 p-5">
        <div className="text-lg font-medium">Output</div>

        {active?.transcript ? (
          <div className="mt-4">
            <div className="text-sm text-slate-300">Transcript</div>
            <div className="mt-2 rounded-xl border border-slate-800 bg-slate-950 p-3 text-sm">
              {active.transcript}
            </div>
          </div>
        ) : null}

        {active?.gloss ? (
          <div className="mt-4">
            <div className="text-sm text-slate-300">Gloss</div>
            <div className="mt-2 rounded-xl border border-slate-800 bg-slate-950 p-3 font-mono text-xs">
              {active.gloss}
            </div>
          </div>
        ) : null}

        <div className="mt-4">
          <div className="text-sm text-slate-300">Tokens</div>
          <TokenView tokens={active?.tokens ?? []} loading={isLoading} />
        </div>

        <div className="mt-4">
          <div className="text-sm text-slate-300">Gesture sequence</div>
          <GestureSequencePlayer gestures={active?.gestures ?? []} loading={isLoading} />
        </div>
      </div>
    </div>
  );
}
