'use client';

import { useState } from 'react';
import { Button } from './ui/button';
import { Separator } from './ui/separator';
import { SpeechRecorder } from './speech-recorder';

export function TranslatorInput({
  text,
  onTextChange,
  onTranslateText,
  onTranslateSpeech,
  loading,
  error,
}: {
  text: string;
  onTextChange: (v: string) => void;
  onTranslateText: () => void;
  onTranslateSpeech: (file: File) => void;
  loading?: boolean;
  error?: string | null;
}) {
  const [audioFile, setAudioFile] = useState<File | null>(null);

  return (
    <div className="rounded-2xl border border-slate-800 bg-slate-900/40 p-5">
      <div className="text-lg font-medium">Input</div>

      <div className="mt-4">
        <div className="text-sm text-slate-300">Text input</div>
        <textarea
          className="mt-2 w-full resize-none rounded-xl border border-slate-800 bg-slate-950 p-3 text-sm outline-none focus:border-slate-600"
          rows={6}
          value={text}
          onChange={(e) => onTextChange(e.target.value)}
          placeholder="Type a sentence…"
        />
        <Button className="mt-3 w-full" onClick={onTranslateText} disabled={loading || !text.trim()}>
          Translate Text
        </Button>
      </div>

      <Separator className="my-5" />

      <div>
        <div className="text-sm text-slate-300">Speech input</div>

        <div className="mt-2">
          <SpeechRecorder disabled={loading} onRecorded={(f) => setAudioFile(f)} />
        </div>

        <div className="mt-3">
          <input
            className="block w-full text-sm text-slate-300 file:mr-4 file:rounded-lg file:border-0 file:bg-slate-800 file:px-4 file:py-2 file:text-sm file:font-medium file:text-white hover:file:bg-slate-700"
            type="file"
            accept="audio/wav,audio/flac,audio/ogg,audio/webm,.wav,.flac,.ogg,.webm"
            onChange={(e) => setAudioFile(e.target.files?.[0] ?? null)}
          />
          <div className="mt-2 text-xs text-slate-400">
            Supported: WAV/FLAC/OGG/WEBM (WEBM is converted to WAV in-browser when possible)
          </div>
        </div>

        <Button
          className="mt-3 w-full"
          onClick={() => audioFile && onTranslateSpeech(audioFile)}
          disabled={loading || !audioFile}
        >
          Transcribe + Translate
        </Button>

        <div className="mt-2 text-xs text-slate-400">Requires backend Vosk model (`VOSK_MODEL_PATH`).</div>
      </div>

      {error ? (
        <div className="mt-4 rounded-xl border border-red-900/40 bg-red-950/40 p-3 text-sm text-red-200">
          {error}
        </div>
      ) : null}
    </div>
  );
}
